"""
# In mysite/signals.py, add to models_to_watch:

from mysite.models import Taxonomy, TaxonomyNode, Item

# Add to models_to_watch list:
# Taxonomy,
# TaxonomyNode,
# Item,

# Note: Catalogue items are NOT in the clientstatic cache
# (too large, filter-dependent). The taxonomy tree IS cached
# separately in catalogue_queries.get_taxonomy_tree().
# Add taxonomy tree cache invalidation:

def invalidate_taxonomy_cache(sender, instance, **kwargs):
    from mysite.models.catalogue import Taxonomy, TaxonomyNode
    from django.core.cache import cache

    if isinstance(instance, (Taxonomy, TaxonomyNode)):
        client = getattr(instance, 'client', None)
        if client:
            cache.delete_pattern(f'taxonomy_tree:{client.client_id}:*')
        else:
            # Global taxonomy — invalidate all clients
            cache.delete_pattern('taxonomy_tree:*')

post_save.connect(invalidate_taxonomy_cache, sender=Taxonomy)
post_save.connect(invalidate_taxonomy_cache, sender=TaxonomyNode)
post_delete.connect(invalidate_taxonomy_cache, sender=Taxonomy)
post_delete.connect(invalidate_taxonomy_cache, sender=TaxonomyNode)

# Note: cache.delete_pattern() requires django-redis backend.
# For LocMemCache (dev), loop through known keys instead.
"""


