"""
# mysite/management/commands/load_sample_products.py

from django.core.management.base import BaseCommand
from mysite.models import Client
from mysite.models.catalogue import (
    Taxonomy, TaxonomyNode, Item, ItemTaxonomyNode
)


class Command(BaseCommand):
    help = 'Load sample product catalogue data for a client'

    def add_arguments(self, parser):
        parser.add_argument('client_id', type=str)

    def handle(self, *args, **options):
        client_id = options['client_id']
        client    = Client.objects.get(client_id=client_id)

        # ── Taxonomies ────────────────────────────────────────────
        cat_tax, _ = Taxonomy.objects.get_or_create(
            client=client, slug='category',
            defaults={'name': 'Category', 'order': 1}
        )

        # Category nodes
        apparel, _ = TaxonomyNode.objects.get_or_create(
            taxonomy=cat_tax, slug='apparel',
            defaults={'name': 'Apparel', 'order': 1, 'path': '001', 'depth': 0}
        )
        mens, _ = TaxonomyNode.objects.get_or_create(
            taxonomy=cat_tax, slug='mens',
            defaults={
                'name': "Men's", 'order': 1, 'depth': 1,
                'parent': apparel, 'path': '001.001'
            }
        )
        womens, _ = TaxonomyNode.objects.get_or_create(
            taxonomy=cat_tax, slug='womens',
            defaults={
                'name': "Women's", 'order': 2, 'depth': 1,
                'parent': apparel, 'path': '001.002'
            }
        )
        electronics, _ = TaxonomyNode.objects.get_or_create(
            taxonomy=cat_tax, slug='electronics',
            defaults={'name': 'Electronics', 'order': 2, 'path': '002', 'depth': 0}
        )

        # Geography taxonomy
        geo_tax, _ = Taxonomy.objects.get_or_create(
            client=client, slug='geography',
            defaults={'name': 'Geography', 'order': 2}
        )
        india, _ = TaxonomyNode.objects.get_or_create(
            taxonomy=geo_tax, slug='india',
            defaults={'name': 'India', 'order': 1, 'path': '001', 'depth': 0}
        )

        # ── Items ─────────────────────────────────────────────────
        products = [
            {
                'item_id':   'tshirt-001',
                'name':      'Classic Cotton T-Shirt',
                'description': 'Comfortable everyday cotton tee. Available in multiple colors.',
                'status':    'active',
                'order':     1,
                'image_url': 'https://picsum.photos/seed/tshirt/400/400',
                'image_alt': 'Classic Cotton T-Shirt',
                'attributes': {
                    'price': 599,
                    'currency': 'INR',
                    'sku': 'APP-TS-001',
                    'material': 'Cotton',
                    'weight_g': 250,
                },
                'nodes': [mens],
            },
            {
                'item_id':   'saree-001',
                'name':      'Silk Banarasi Saree',
                'description': 'Traditional Banarasi silk saree with gold zari work.',
                'status':    'active',
                'order':     2,
                'image_url': 'https://picsum.photos/seed/saree/400/400',
                'image_alt': 'Silk Banarasi Saree',
                'attributes': {
                    'price': 4999,
                    'currency': 'INR',
                    'sku': 'APP-SR-001',
                    'material': 'Silk',
                    'occasion': 'Formal',
                },
                'nodes': [womens],
            },
            {
                'item_id':   'phone-001',
                'name':      'Wireless Earbuds Pro',
                'description': 'Premium wireless earbuds with active noise cancellation.',
                'status':    'active',
                'order':     3,
                'image_url': 'https://picsum.photos/seed/earbuds/400/400',
                'image_alt': 'Wireless Earbuds Pro',
                'attributes': {
                    'price': 2499,
                    'currency': 'INR',
                    'sku': 'ELC-EB-001',
                    'battery_hours': 8,
                    'connectivity': 'Bluetooth 5.3',
                },
                'nodes': [electronics],
            },
        ]

        for p in products:
            nodes = p.pop('nodes')
            item, created = Item.objects.update_or_create(
                client=client,
                item_id=p['item_id'],
                defaults=p
            )
            for node in nodes:
                ItemTaxonomyNode.objects.get_or_create(
                    item=item, node=node,
                    defaults={'is_primary': True}
                )
            # All items belong to India geography
            ItemTaxonomyNode.objects.get_or_create(
                item=item, node=india,
                defaults={'is_primary': False}
            )
            self.stdout.write(
                f"{'Created' if created else 'Updated'}: {item.item_id}"
            )

        self.stdout.write(self.style.SUCCESS(
            f'Sample products loaded for {client_id}'
        ))
"""


# ============================================================
# H. PERFORMANCE STRATEGY NOTES
# ============================================================
"""
1. JSONB GIN index (PostgreSQL only):
   Enables fast filtering on attributes -> e.g. ?attr_color=red
   Added via RunSQL in migration (see section A above).
   Query: Item.objects.filter(attributes__color='red') uses this index.

2. Materialized path for tree queries:
   path__startswith="001.002." is a B-tree prefix scan — very fast.
   Much faster than recursive CTE for read-heavy catalogue pages.
   Trade-off: path must be recomputed on node move (rare operation).

3. N+1 prevention:
   All Item queries use select_related + prefetch_related with to_attr.
   Never call item.images.all() in a template loop — always prefetch.

4. Taxonomy tree caching:
   get_taxonomy_tree() caches per client+slug for 1 hour.
   Invalidated on TaxonomyNode post_save/post_delete signals.
   For 20k+ items, taxonomy trees are small (hundreds of nodes)
   and safe to cache in Redis.

5. Catalogue items are NOT in clientstatic cache:
   Items are filter-dependent and too numerous to cache as a flat list.
   The clientstatic cache holds structural/theme data only.
   Item queries hit the DB with proper indexes — fast enough for 20k items.

6. Pagination:
   Always paginate — never load all items. Default 24/page.
   Django Paginator with LIMIT/OFFSET. For very large datasets
   (100k+), switch to keyset pagination (WHERE id > last_id).

7. SQLite vs PostgreSQL:
   JSONB GIN index and text_pattern_ops are PostgreSQL-only.
   attributes__color filter works in SQLite without the index (slower).
   path__startswith works in SQLite without text_pattern_ops (slower).
   Dev performance is acceptable; production needs PostgreSQL.
"""